// docgraphPromptCapBytes caps the size of prompt-metadata strings parsed
// from doc frontmatter. FEAT-022 §9 / Stage D2. Package-level variable so
// tests can lower the cap; production callers must not mutate it.
var docgraphPromptCapBytes = evidence.DefaultMaxPromptBytes

// ErrPromptMetadataOversize is returned when a doc's `prompt:` metadata
// exceeds the configured cap. Graph-build callers treat it as fatal so the
// build stops with an actionable error rather than silently dropping the
// document via a parse_error issue.
var ErrPromptMetadataOversize = errors.New("docgraph prompt metadata exceeds cap")

const (
	frontmatterSeparator = "---"
)

var (
	ErrNotDocGraphDocument = errors.New("not a doc graph document")
)

// IssueKind is the machine-readable category for a GraphIssue.
type IssueKind string

const (
	IssueDuplicateID         IssueKind = "duplicate_id"
	IssueParseError          IssueKind = "parse_error"
	IssueMissingDep          IssueKind = "missing_dep"
	IssueIDPathMissing       IssueKind = "id_path_missing"
	IssueIDPathMismatch      IssueKind = "id_path_mismatch"
	IssueRequiredRootMissing IssueKind = "required_root_missing"
	IssueCascadeUnknown      IssueKind = "cascade_unknown"
	IssueCycle               IssueKind = "cycle"
)

// GraphIssue is a structured description of a problem in the document graph.
// Kind groups issues for UI rollups; Path and ID locate the offending document
// (both may be empty when the issue is not tied to a single file, e.g. a
// cycle). RelatedPath points at a second file when the issue describes a
// relationship, e.g. the pre-existing document a duplicate ID collides with.
type GraphIssue struct {
	Kind        IssueKind `json:"kind"`
	Path        string    `json:"path,omitempty"`
	ID          string    `json:"id,omitempty"`
	Message     string    `json:"message"`
	RelatedPath string    `json:"relatedPath,omitempty"`
}

// SuggestUniqueID returns a deterministic unique ID suggestion for a duplicate.
// Given the same (id, path) inputs it always returns the same output. The
// suggestion appends a short 8-character hex hash of the path so operators can
// copy-paste a drop-in replacement without collision anxiety.
func SuggestUniqueID(id, path string) string {
	trimmedID := strings.TrimSpace(id)
	trimmedPath := strings.TrimSpace(path)
	sum := sha1.Sum([]byte(trimmedPath))
	suffix := hex.EncodeToString(sum[:])[:8]
	if trimmedID == "" {
		return "doc-" + suffix
	}
	return trimmedID + "-" + suffix
}

type ReviewMetadata struct {
	SelfHash   string            `yaml:"self_hash" json:"self_hash"`
	Deps       map[string]string `yaml:"deps" json:"deps"`
	ReviewedAt string            `yaml:"reviewed_at" json:"reviewed_at"`
}

type Document struct {
	ID         string
	Path       string
	Title      string
	DependsOn  []string
	Inputs     []string
	Review     ReviewMetadata
	ParkingLot bool
	Prompt     string
	Dependents []string
	ExecDef    *DocExecDef

	contentHash string

	frontmatter   *yaml.Node
	body          string
	bodyLinkTexts []string
}

type StaleReason struct {
	ID      string   `json:"id"`
	Path    string   `json:"path"`
	Reasons []string `json:"reasons"`
}

type Graph struct {
	RootDir    string
	Documents  map[string]*Document
	PathToID   map[string]string
	Dependents map[string][]string
	Issues     []GraphIssue
	// Warnings is kept for callers still rendering the flat string list; it is
	// derived from Issues at the end of graph construction via MessageLines().
	Warnings []string
}

// MessageLines returns the human-readable message strings for a set of issues,
// sorted for stable output. Callers that historically consumed
// Graph.Warnings can use issues.MessageLines() once migrated.
func MessageLines(issues []GraphIssue) []string {
	if len(issues) == 0 {
		return nil
	}
	out := make([]string, 0, len(issues))
	for _, issue := range issues {
		out = append(out, issue.Message)
	}
	sort.Strings(out)
	return out
}

type GraphConfig struct {
	Roots    []string            `yaml:"roots"`
	IDToPath map[string]string   `yaml:"id_to_path"`
	Cascade  map[string][]string `yaml:"cascade"`
	IDMap    map[string]string   `yaml:"id_map"`
	Required []string            `yaml:"required_roots"`
}

func BuildGraph(workingDir string) (*Graph, error) {
	return buildGraph(workingDir, nil)
}

func BuildGraphWithConfig(workingDir string) (*Graph, error) {
	configs, err := LoadGraphConfigs(workingDir)
	if err != nil {
		return nil, err
	}
	if len(configs) == 0 {
		return BuildGraph(workingDir)
	}

	roots := make([]string, 0, len(configs))
	for _, cfg := range configs {
		for _, root := range cfg.Roots {
			if root == "" {
				continue
			}
			roots = append(roots, filepath.Join(workingDir, root))
		}
	}
	if len(roots) == 0 {
		return BuildGraph(workingDir)
	}

	graph, err := buildGraph(workingDir, roots)
	if err != nil {
		return nil, err
	}
	graph.applyConfig(configs)
	return graph, nil
}

func buildGraph(workingDir string, roots []string) (*Graph, error) {
	files, err := findMarkdownFiles(workingDir, roots)
	if err != nil {
		return nil, err
	}

	cleanRoot := filepath.Clean(workingDir)
	documents := make(map[string]*Document)
	pathToID := make(map[string]string)
	issues := []GraphIssue{}
	for _, filePath := range files {
		doc, err := ParseDocument(filePath)
		if err != nil {
			if errors.Is(err, ErrNotDocGraphDocument) {
				continue
			}
			if errors.Is(err, ErrPromptMetadataOversize) {
				return nil, err
			}
			issues = append(issues, GraphIssue{
				Kind:    IssueParseError,
				Path:    relPath(cleanRoot, filePath),
				Message: fmt.Sprintf("%s: %v", filePath, err),
			})
			continue
		}
		if existing, exists := documents[doc.ID]; exists {
			issues = append(issues, GraphIssue{
				Kind:        IssueDuplicateID,
				Path:        relPath(cleanRoot, filePath),
				ID:          doc.ID,
				Message:     fmt.Sprintf("duplicate document id %q in %q", doc.ID, filePath),
				RelatedPath: existing.Path,
			})
			continue
		}
		doc.Path = relPath(cleanRoot, filePath)
		documents[doc.ID] = doc
		pathToID[doc.Path] = doc.ID
	}

	g := &Graph{
		RootDir:   cleanRoot,
		Documents: documents,
		PathToID:  pathToID,
		Issues:    issues,
	}
	g.resolveBodyLinks()
	g.buildDependents()
	g.detectMissingDeps()
	g.detectCycles()
	g.applyConfigDefaults()
	g.finalizeWarnings()
	return g, nil
}

// detectMissingDeps emits missing_dep issues for every declared dependency
// that does not resolve to a document in the graph. Runs after body-link
// resolution so link targets are already promoted to DependsOn.
func (g *Graph) detectMissingDeps() {
	for _, id := range sortedDocIDs(g.Documents) {
		doc := g.Documents[id]
		if doc == nil {
			continue
		}
		for _, dep := range doc.DependsOn {
			if _, ok := g.Documents[dep]; ok {
				continue
			}
			g.Issues = append(g.Issues, GraphIssue{
				Kind:    IssueMissingDep,
				Path:    doc.Path,
				ID:      dep,
				Message: fmt.Sprintf("document %q declares dependency %q which is not in the graph", doc.ID, dep),
			})
		}
	}
}

// sortedDocIDs returns the IDs of docs sorted for stable issue ordering.

package docgraph

import (
	"bytes"
	"fmt"
	"sort"
	"strings"

	"gopkg.in/yaml.v3"
)

// DocFrontmatter holds the parsed ddx: (or legacy dun:) frontmatter block.
type DocFrontmatter struct {
	ID         string      `yaml:"id"`
	DependsOn  []string    `yaml:"depends_on"`
	Prompt     string      `yaml:"prompt"`
	Inputs     []string    `yaml:"inputs"`
	Review     DocReview   `yaml:"review"`
	ParkingLot bool        `yaml:"parking_lot"`
	Exec       *DocExecDef `yaml:"execution"`
}

// DocExecDef describes an execution definition embedded in a graph document.
// The YAML key is "execution" (matching the ddx: frontmatter convention).
// Fields are flat to match the authored document format:
//
//	ddx:
//	  execution:
//	    kind: command
//	    required: true
//	    command: ["make", "test"]
//	    cwd: cli
//	    timeout_ms: 120000
//	    comparison: lower-is-better
//	    thresholds:
//	      ratchet: 250
//	      unit: ms
//	    metric:
//	      metric_id: MET-API-LATENCY
//
// ArtifactIDs is optional; when absent, the document's depends_on list is used
// to determine which artifacts this execution is linked to. Comparison,
// Thresholds, and Metric declare the ratchet evaluation applied by the
// landing gate when the command exits 0: the gate parses a numeric observed
// value out of stdout and compares it against the ratchet threshold before
// allowing the attempt to merge.
type DocExecDef struct {
	Kind        string            `yaml:"kind"`
	Command     []string          `yaml:"command"`
	Cwd         string            `yaml:"cwd"`
	Env         map[string]string `yaml:"env"`
	TimeoutMS   int               `yaml:"timeout_ms"`
	ArtifactIDs []string          `yaml:"artifact_ids"`
	Required    bool              `yaml:"required"`
	Active      bool              `yaml:"active"`
	Comparison  string            `yaml:"comparison"`
	Thresholds  *DocThresholds    `yaml:"thresholds"`
	Metric      *DocMetricSpec    `yaml:"metric"`
}

// DocThresholds captures the ratchet policy declared alongside an execution
// definition. Ratchet is the value the landing gate enforces; unit is only
// used for evidence reporting.
type DocThresholds struct {
	Ratchet float64 `yaml:"ratchet"`
	Warn    float64 `yaml:"warn"`
	Unit    string  `yaml:"unit"`
}

// DocMetricSpec names the metric artifact a gate observes. Optional — a gate
// without a metric can still declare thresholds, in which case the definition
// ID is used as the metric identifier on ratchet evidence.
type DocMetricSpec struct {
	MetricID string `yaml:"metric_id"`
	Unit     string `yaml:"unit"`
}

// DocReview holds staleness tracking metadata.
type DocReview struct {
	SelfHash   string            `yaml:"self_hash"`
	Deps       map[string]string `yaml:"deps"`
	ReviewedAt string            `yaml:"reviewed_at"`
}

// Frontmatter is the parsed result from a markdown file.
type Frontmatter struct {
	Doc            DocFrontmatter
	Raw            *yaml.Node
	HasFrontmatter bool
	// Namespace records which prefix was found: "ddx" or "dun".
	Namespace string
}

// ParseFrontmatter parses YAML frontmatter from markdown content.
// It reads both ddx: and dun: namespaces (preferring ddx: if both present).
// Returns the parsed frontmatter, the body text after the closing ---, and any error.
func ParseFrontmatter(content []byte) (Frontmatter, string, error) {
	frontmatterText, body, ok := splitFrontmatter(content)
	if !ok {
		return Frontmatter{}, string(content), nil
	}

	trimmed := strings.TrimSpace(frontmatterText)

	// Try ddx: first, then dun: for backward compatibility
	var doc DocFrontmatter
	namespace := ""

	var ddxWrapper struct {
		DDx DocFrontmatter `yaml:"ddx"`
	}
	if err := yaml.Unmarshal([]byte(trimmed), &ddxWrapper); err != nil {
		return Frontmatter{}, "", fmt.Errorf("parse frontmatter: %w", err)
	}
	if ddxWrapper.DDx.ID != "" {
		doc = ddxWrapper.DDx
		namespace = "ddx"
	} else {
		var dunWrapper struct {
			Dun DocFrontmatter `yaml:"dun"`
		}
		if err := yaml.Unmarshal([]byte(trimmed), &dunWrapper); err != nil {
			return Frontmatter{}, "", fmt.Errorf("parse frontmatter: %w", err)
		}
		if dunWrapper.Dun.ID != "" {
			doc = dunWrapper.Dun
			namespace = "dun"
		}
	}

	var node yaml.Node
	if err := yaml.Unmarshal([]byte(trimmed), &node); err != nil {
		return Frontmatter{}, "", fmt.Errorf("parse frontmatter node: %w", err)
	}

	var root *yaml.Node
	if len(node.Content) > 0 {
		root = node.Content[0]
	}

	return Frontmatter{
		Doc:            doc,
		Raw:            root,
		HasFrontmatter: true,
		Namespace:      namespace,
	}, body, nil
}

// MigrateLegacyDunFrontmatter converts top-level `dun:` metadata to `ddx:`.
//
// Migration is lossless for fields:
//   - If both `ddx` and `dun` are present, keys from `dun` are merged into `ddx`
//     when missing.
//   - If only `dun` is present, it is renamed to `ddx`.
//   - If `ddx` is already present and no other legacy-compatible namespace exists,
//     no changes are made.
func MigrateLegacyDunFrontmatter(root *yaml.Node) bool {
	if root == nil || root.Kind != yaml.MappingNode {
		return false
	}

	ddxNode := findMappingValue(root, "ddx")
	dunNode := findMappingValue(root, "dun")
	if dunNode == nil {
		return false
	}

	if ddxNode == nil {
		dunKey := findMappingKey(root, "dun")
		if dunKey != nil {
			dunKey.Value = "ddx"
		}
		return true
	}

	// Merge legacy keys into ddx only when missing.
	mergeIntoDDX(ddxNode, dunNode)

	removeMappingKey(root, "dun")
	return true
}

func splitFrontmatter(content []byte) (string, string, bool) {
	if !bytes.HasPrefix(content, []byte("---")) {
		return "", string(content), false
	}

	firstLineEnd := bytes.IndexByte(content, '\n')
	if firstLineEnd == -1 {
		return "", string(content), false
	}

	firstLine := bytes.TrimRight(content[:firstLineEnd], "\r")
	if !bytes.Equal(firstLine, []byte("---")) {
		return "", string(content), false
	}

	rest := content[firstLineEnd+1:]
	idx := 0
	for idx <= len(rest) {
		lineEnd := bytes.IndexByte(rest[idx:], '\n')
		if lineEnd == -1 {
			lineEnd = len(rest) - idx
		}
		line := rest[idx : idx+lineEnd]
		lineTrimmed := bytes.TrimRight(line, "\r")
		if bytes.Equal(lineTrimmed, []byte("---")) {
			frontmatter := rest[:idx]
			bodyStart := idx + lineEnd
			if idx+lineEnd < len(rest) && rest[idx+lineEnd] == '\n' {
				bodyStart = idx + lineEnd + 1
			}
			return string(frontmatter), string(rest[bodyStart:]), true
		}
		if idx+lineEnd >= len(rest) {
			break
		}
		idx += lineEnd + 1
	}

package cmd

import (
	"bytes"
	"os"
	"path/filepath"
	"strings"
