 68	// SuggestUniqueID returns a deterministic unique ID suggestion for a duplicate.
 69	// Given the same (id, path) inputs it always returns the same output. The
 70	// suggestion appends a short 8-character hex hash of the path so operators can
 71	// copy-paste a drop-in replacement without collision anxiety.
 72	func SuggestUniqueID(id, path string) string {
 73		trimmedID := strings.TrimSpace(id)
 74		trimmedPath := strings.TrimSpace(path)
 75		sum := sha1.Sum([]byte(trimmedPath))
